  <svg viewBox="0 0 700 320" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="28" fill="#fafafa" font-size="14" font-weight="700" font-family="sans-serif">Die Vier Gesichter der "Miner-Kapitulation" (2018-2024)</text>
    <line x1="55" y1="150" x2="655" y2="150" stroke="#3f3f46" stroke-width="1.5"/>
    <g font-family="sans-serif" text-anchor="middle">
      <circle cx="100" cy="150" r="10" fill="#f87171"/><text x="100" y="154" fill="#111113" font-size="11" font-weight="700">1</text>
      <text x="100" y="120" fill="#e4e4e7" font-size="15" font-weight="700">2018</text>
      <text x="100" y="178" fill="#f87171" font-size="13" font-weight="700">Bankrott</text>
      <text x="100" y="198" fill="#a1a1aa" font-size="12.5">Giga Watt und kleine</text>
      <text x="100" y="214" fill="#a1a1aa" font-size="12.5">Miner schließen</text>

      <circle cx="270" cy="150" r="10" fill="#fbbf24"/><text x="270" y="154" fill="#111113" font-size="11" font-weight="700">2</text>
